+/// Get path to llama-imatrix tool
+fn getImatrixToolPath(allocator: std.mem.Allocator) ![]u8 {
+    // Use compiled llama-imatrix from vendor/llama.cpp/build/bin/
+    const cwd = std.fs.cwd();
+    const path = "vendor/llama.cpp/build/bin/llama-imatrix";
+
+    // Verify it exists
+    cwd.access(path, .{}) catch {
+        return error.ImatrixToolNotFound;
+    };
+
+    return try allocator.dupe(u8, path);
+}
+
+/// Get path to default calibration dataset
+fn getCalibrationDataPath(allocator: std.mem.Allocator) ![]u8 {
+    return try allocator.dupe(u8, "data/calibration.txt");
+}
+
+/// Get path to cached imatrix file for a model
+pub fn getImatrixPath(allocator: std.mem.Allocator, model_path: []const u8) ![]u8 {
+    const hash = try model_hash.computeModelHash(allocator, model_path);
+    defer allocator.free(hash);
+
+    const cache_dir = try model_hash.getCacheDir(allocator);
+    defer allocator.free(cache_dir);
+
+    const imatrix_dir = try std.fmt.allocPrint(allocator, "{s}/imatrix", .{cache_dir});
+    defer allocator.free(imatrix_dir);
+
+    // Ensure imatrix directory exists
+    std.fs.cwd().makePath(imatrix_dir) catch |err| {
+        if (err != error.PathAlreadyExists) return err;
+    };
+
+    return try std.fmt.allocPrint(
+        allocator,
+        "{s}/imatrix/{s}.gguf",
+        .{ cache_dir, hash }
+    );
+}
+
+/// Check if imatrix file exists and is valid
+pub fn imatrixExists(allocator: std.mem.Allocator, model_path: []const u8) bool {
+    const imatrix_path = getImatrixPath(allocator, model_path) catch return false;
+    defer allocator.free(imatrix_path);
+
+    // Check if file exists
+    const file = std.fs.cwd().openFile(imatrix_path, .{}) catch return false;
+    defer file.close();
+
+    // Check if it's reasonably sized (at least 1KB)
+    const stat = file.stat() catch return false;
+    if (stat.size < 1024) return false;
+
+    // Check GGUF magic bytes
+    var magic: [4]u8 = undefined;
+    _ = file.readAll(&magic) catch return false;
+
+    return std.mem.eql(u8, &magic, "GGUF");
+}
+
+/// Generate importance matrix for a model
+pub fn generateImatrix(
+    allocator: std.mem.Allocator,
+    model_path: []const u8,
+    output_path: []const u8,
+) !void {
+    std.debug.print("\n📊 Generating importance matrix...\n", .{});
+    std.debug.print("  Model: {s}\n", .{model_path});
+    std.debug.print("  This will take 5-10 minutes...\n", .{});
+
+    const tool_path = try getImatrixToolPath(allocator);
+    defer allocator.free(tool_path);
+
+    const calibration_path = try getCalibrationDataPath(allocator);
+    defer allocator.free(calibration_path);
+
+    // Verify calibration data exists
+    std.fs.cwd().access(calibration_path, .{}) catch {
+        std.debug.print("  ❌ Calibration data not found: {s}\n", .{calibration_path});
+        return error.CalibrationDataMissing;
+    };
+
+    const start_time = std.time.milliTimestamp();
+
+    // Build command: llama-imatrix -m model.gguf -f calibration.txt -o imatrix.gguf -ngl 99
+    var argv = std.ArrayList([]const u8).initCapacity(allocator, 16) catch unreachable;
+    defer argv.deinit(allocator);
+
+    try argv.append(allocator, tool_path);
+    try argv.append(allocator, "-m");
+    try argv.append(allocator, model_path);
+    try argv.append(allocator, "-f");
+    try argv.append(allocator, calibration_path);
+    try argv.append(allocator, "-o");
+    try argv.append(allocator, output_path);
+    try argv.append(allocator, "-ngl");
+    try argv.append(allocator, "99"); // Offload all layers to GPU
+    try argv.append(allocator, "--chunks");
+    try argv.append(allocator, "100"); // Process 100 chunks (reasonable for calibration)
+    try argv.append(allocator, "--no-ppl"); // Skip perplexity calculation (faster)
+
+    // Execute command
+    var child = std.process.Child.init(argv.items, allocator);
+    child.stdout_behavior = .Inherit;
+    child.stderr_behavior = .Inherit;
+
+    const term = try child.spawnAndWait();
+
+    switch (term) {
+        .Exited => |code| {
+            if (code != 0) {
+                std.debug.print("  ❌ Imatrix generation failed with exit code {d}\n", .{code});
+                return error.ImatrixGenerationFailed;
+            }
+        },
+        else => {
+            std.debug.print("  ❌ Imatrix generation terminated abnormally\n", .{});
+            return error.ImatrixGenerationFailed;
+        },
+    }
+
+    const elapsed_ms = std.time.milliTimestamp() - start_time;
+    const elapsed_sec = @as(f32, @floatFromInt(elapsed_ms)) / 1000.0;
+    const elapsed_min = elapsed_sec / 60.0;
+
+    std.debug.print("  ✅ Importance matrix generated in {d:.1} min\n", .{elapsed_min});
+    std.debug.print("  Saved to: {s}\n\n", .{output_path});
+}
+
+/// Generate imatrix if it doesn't exist
+pub fn ensureImatrix(allocator: std.mem.Allocator, model_path: []const u8) !?[]const u8 {
+    // Check if imatrix already exists
+    if (imatrixExists(allocator, model_path)) {
+        const imatrix_path = try getImatrixPath(allocator, model_path);
+        std.debug.print("  ✅ Using cached importance matrix\n", .{});
+        return imatrix_path;
+    }
+
+    // Generate imatrix
+    const imatrix_path = try getImatrixPath(allocator, model_path);
+    errdefer allocator.free(imatrix_path);
+
+    try generateImatrix(allocator, model_path, imatrix_path);
+
+    return imatrix_path;
+}

