+/// Quantize a model file to a different quantization type
+/// This is used for build-time requantization to reduce model size
+pub fn modelQuantize(
+    input_path: []const u8,
+    output_path: []const u8,
+    ftype: c.llama_ftype,
+) !u32 {
+    // Create null-terminated paths for C API
+    var input_buf: [4096]u8 = undefined;
+    var output_buf: [4096]u8 = undefined;
+
+    if (input_path.len >= input_buf.len) return error.PathTooLong;
+    if (output_path.len >= output_buf.len) return error.PathTooLong;
+
+    @memcpy(input_buf[0..input_path.len], input_path);
+    input_buf[input_path.len] = 0;
+
+    @memcpy(output_buf[0..output_path.len], output_path);
+    output_buf[output_path.len] = 0;
+
+    // Get default quantization params and customize
+    var params = c.llama_model_quantize_default_params();
+    params.ftype = ftype;
+    params.nthread = 0; // Use all available cores
+    params.allow_requantize = true; // CRITICAL: Allow quantizing already-quantized tensors
+    params.pure = true; // Simple quantization without advanced optimizations
+
+    // Call llama.cpp quantization function
+    const result = c.llama_model_quantize(&input_buf, &output_buf, &params);
+    if (result != 0) {
+        return error.QuantizationFailed;
+    }
+
+    return result;
+}
