+pub fn tokenizeWithImages(
+    ctx: *VisionContext,
+    chunks: *InputChunks,
+    prompt: []const u8,
+    images: []const *ImageBitmap,
+) !void {
+    var prompt_buf: [8192]u8 = undefined;
+    if (prompt.len >= prompt_buf.len) return error.PromptTooLong;
+    @memcpy(prompt_buf[0..prompt.len], prompt);
+    prompt_buf[prompt.len] = 0;
+
+    var input_text = mtmd.mtmd_input_text{
+        .text = &prompt_buf,
+        .add_special = true,
+        .parse_special = true,
+    };
+
+    var bitmaps = try std.heap.page_allocator.alloc(*mtmd.mtmd_bitmap, images.len);
+    defer std.heap.page_allocator.free(bitmaps);
+
+    for (images, 0..) |img, i| {
+        bitmaps[i] = img.handle;
+    }
+
+    const result = mtmd.mtmd_tokenize(
+        ctx.handle,
+        chunks.handle,
+        &input_text,
+        @ptrCast(bitmaps.ptr),
+        images.len,
+    );
+
+    if (result != 0) {
+        return switch (result) {
+            1 => error.ImageCountMismatch,
+            2 => error.ImagePreprocessingFailed,
+            else => error.TokenizationFailed,
+        };
+    }
