+/// Validate mmproj file (check GGUF magic)
+pub fn validateMmproj(mmproj_path: []const u8) !bool {
+    const file = std.fs.cwd().openFile(mmproj_path, .{}) catch return false;
+    defer file.close();
+
+    var magic: [4]u8 = undefined;
+    const bytes_read = file.readAll(&magic) catch return false;
+    if (bytes_read != 4) return false;
+
+    return std.mem.eql(u8, &magic, "GGUF");
+}
