+const std = @import("std");
+const llama = @import("llama.zig");
+const model_hash = @import("model_hash.zig");
+
+/// Quantization target types
+/// IQ* types require importance matrix (imatrix) for best quality
+pub const QuantizationType = enum {
+    IQ2_XS, // 2.31 bpw - most aggressive (REQUIRES imatrix)
+    Q2_K, // 2.96 bpw - aggressive (works without imatrix)
+    Q3_K_S, // 3.41 bpw - balanced approach
+    Q3_K_M, // 3.66 bpw - quality-focused
+
+    pub fn toString(self: QuantizationType) []const u8 {
+        return switch (self) {
+            .IQ2_XS => "IQ2_XS",
+            .Q2_K => "Q2_K",
+            .Q3_K_S => "Q3_K_S",
+            .Q3_K_M => "Q3_K_M",
+        };
+    }
+
+    pub fn toLlamaFtype(self: QuantizationType) llama.c.llama_ftype {
+        return switch (self) {
+            .IQ2_XS => llama.c.LLAMA_FTYPE_MOSTLY_IQ2_XS,
+            .Q2_K => llama.c.LLAMA_FTYPE_MOSTLY_Q2_K,
+            .Q3_K_S => llama.c.LLAMA_FTYPE_MOSTLY_Q3_K_S,
+            .Q3_K_M => llama.c.LLAMA_FTYPE_MOSTLY_Q3_K_M,
+        };
+    }
+
+    pub fn getBitsPerWeight(self: QuantizationType) f32 {
+        return switch (self) {
+            .IQ2_XS => 2.31,
+            .Q2_K => 2.96,
+            .Q3_K_S => 3.41,
+            .Q3_K_M => 3.66,
+        };
+    }
+
+    pub fn getQualityImpact(self: QuantizationType) []const u8 {
+        return switch (self) {
+            .Q3_K_M => "minimal quality impact (~0.86 ppl increase)",
+            .Q3_K_S => "moderate quality impact (~1.6 ppl increase)",
+            .Q2_K => "noticeable quality impact (~3.5 ppl increase)",
+            .IQ2_XS => "significant quality impact (~5 ppl increase, but smallest size)",
+        };
+    }
+
+    pub fn requiresImatrix(self: QuantizationType) bool {
+        return switch (self) {
+            .IQ2_XS => true,
+            .Q2_K, .Q3_K_S, .Q3_K_M => false,
+        };
+    }
+};
+
+/// Intelligently select optimal quantization based on resource constraints
+/// Returns null if no requantization is needed
+pub fn selectOptimalQuantization(
+    model_size_gb: f32,
+    system_memory_gb: f32,
+    memory_percent: f32,
+) ?QuantizationType {
+    const target_memory = system_memory_gb * (memory_percent / 100.0);
+    const usage_ratio = model_size_gb / target_memory;
+
+    // Intelligent selection based on resource constraints
+    if (usage_ratio < 0.50) {
+        // Plenty of space, no requantization needed
+        return null;
+    } else if (usage_ratio < 0.70) {
+        // Tight fit - minimize quality loss
+        return .Q3_K_M;
+    } else if (usage_ratio < 0.90) {
+        // Very tight - balanced approach
+        return .Q3_K_S;
+    } else if (usage_ratio < 1.05) {
+        // Extremely tight - use Q2_K (works without imatrix)
+        return .Q2_K;
+    } else {
+        // Critically tight - use IQ2_XS (requires imatrix, smallest size)
+        return .IQ2_XS;
+    }
+}
+
+/// Calculate expected output size after requantization
+pub fn getRequantizedSize(original_size_gb: f32, target_type: QuantizationType) f32 {
+    // Assume original is Q4_K_M (4.8 bpw)
+    const original_bpw: f32 = 4.8;
+    const target_bpw = target_type.getBitsPerWeight();
+    return original_size_gb * (target_bpw / original_bpw);
+}
