+/// Validate cached requantized file
+/// Three-tier validation: file size + GGUF magic bytes + optional deep check
+pub fn isCachedFileValid(path: []const u8, expected_size_gb: f32) bool {
+    const file = std.fs.cwd().openFile(path, .{}) catch return false;
+    defer file.close();
+
+    // Tier 1: File size check (±30% tolerance)
+    // Wider tolerance because GGUF metadata and per-layer quantization varies
+    const stat = file.stat() catch return false;
+    const expected_bytes: u64 = @intFromFloat(expected_size_gb * 1024.0 * 1024.0 * 1024.0);
+    const min_bytes = @as(u64, @intFromFloat(@as(f32, @floatFromInt(expected_bytes)) * 0.70));
+    const max_bytes = @as(u64, @intFromFloat(@as(f32, @floatFromInt(expected_bytes)) * 1.30));
+
+    if (stat.size < min_bytes or stat.size > max_bytes) {
+        std.debug.print("  Warning: Cached file size mismatch (expected ~{d:.1} GB, got {d:.1} GB)\n", .{
+            expected_size_gb,
+            @as(f32, @floatFromInt(stat.size)) / (1024.0 * 1024.0 * 1024.0),
+        });
+        return false;
+    }
+
+    // Tier 2: GGUF magic bytes check
+    var magic: [4]u8 = undefined;
+    _ = file.readAll(&magic) catch return false;
+
+    if (!std.mem.eql(u8, &magic, "GGUF")) {
+        std.debug.print("  Warning: Cached file is not a valid GGUF file\n", .{});
+        return false;
+    }
+
+    // File looks valid
+    return true;
+}
