+/// Requantize a model file with comprehensive error handling
+pub fn requantizeModel(
+    allocator: std.mem.Allocator,
+    input_path: []const u8,
+    output_path: []const u8,
+    target_type: QuantizationType,
+) !void {
+    const type_name = target_type.toString();
+    const quality_impact = target_type.getQualityImpact();
+
+    std.debug.print("\n⚡ Requantizing to {s}...\n", .{type_name});
+    std.debug.print("  Strategy: {s}\n", .{quality_impact});
+
+    // Pre-check disk space (need ~1.5x model size for temp files)
+    const file = try std.fs.cwd().openFile(input_path, .{});
+    defer file.close();
+    const stat = try file.stat();
+    const model_size_gb = @as(f32, @floatFromInt(stat.size)) / (1024.0 * 1024.0 * 1024.0);
+
+    const needed_gb = model_size_gb * 1.5; // 50% buffer for temp files
+    if (!hasEnoughDiskSpace(needed_gb)) {
+        std.debug.print("  ❌ Error: Insufficient disk space (need ~{d:.1} GB free)\n", .{needed_gb});
+        return error.InsufficientDiskSpace;
+    }
+
+    // Write to temporary file first (atomic operation)
+    const temp_path = try std.fmt.allocPrint(allocator, "{s}.tmp", .{output_path});
+    defer allocator.free(temp_path);
+
+    std.debug.print("  Requantizing (this may take 2-3 minutes)...\n", .{});
+
+    const start_time = std.time.milliTimestamp();
+
+    // Call llama.cpp quantization
+    const ftype = target_type.toLlamaFtype();
+    const result = llama.modelQuantize(input_path, temp_path, ftype) catch |err| {
+        std.debug.print("  ❌ Quantization failed: {}\n", .{err});
+        // Clean up temp file
+        std.fs.cwd().deleteFile(temp_path) catch {};
+        return err;
+    };
+
+    // Verify output file was created with reasonable size
+    const output_file = std.fs.cwd().openFile(temp_path, .{}) catch {
+        std.debug.print("  ❌ Output file not created\n", .{});
+        return error.CorruptedOutput;
+    };
+    defer output_file.close();
+
+    const output_stat = try output_file.stat();
+    const expected_size = getRequantizedSize(model_size_gb, target_type);
+    const output_size_gb = @as(f32, @floatFromInt(output_stat.size)) / (1024.0 * 1024.0 * 1024.0);
+
+    // Validate size is reasonable (±30% tolerance)
+    // GGUF metadata and per-layer quantization causes variance from simple calculation
+    if (output_size_gb < expected_size * 0.70 or output_size_gb > expected_size * 1.30) {
+        std.debug.print("  ❌ Output size unexpected (expected ~{d:.1} GB, got {d:.1} GB)\n", .{ expected_size, output_size_gb });
+        std.fs.cwd().deleteFile(temp_path) catch {};
+        return error.CorruptedOutput;
+    }
+
+    // Atomic rename
+    try std.fs.cwd().rename(temp_path, output_path);
+
+    const elapsed_ms = std.time.milliTimestamp() - start_time;
+    const elapsed_sec = @as(f32, @floatFromInt(elapsed_ms)) / 1000.0;
+
+    std.debug.print("  ✅ Requantized in {d:.1}s\n", .{elapsed_sec});
+    std.debug.print("  Model size: {d:.1} GB → {d:.1} GB ({d:.0}% reduction)\n", .{
+        model_size_gb,
+        output_size_gb,
+        (1.0 - output_size_gb / model_size_gb) * 100.0,
+    });
+
+    _ = result; // Suppress unused warning
+}
